// ─── Icon renderer ────────────────────────────────────────────────────────────

function SkillIcon({
  iconData,
  isDark,
  size = 28,
}: {
  iconData: SkillIconType;
  isDark: boolean;
  size?: number;
}) {
  if (iconData.kind === "img") {
    return (
      // eslint-disable-next-line @next/next/no-img-element
      <img
        src={iconData.src}
        alt=""
        width={size}
        height={size}
        loading="lazy"
        style={{ objectFit: "contain" }}
      />
    );
  }

  // Monochrome icons (black brand color) need to flip on dark backgrounds
  const fill =
    iconData.invertDark && isDark
      ? "#E6EDF3"
      : `#${iconData.hex}`;

  return (
    <svg
      viewBox="0 0 24 24"
      width={size}
      height={size}
      fill={fill}
      aria-hidden="true"
      style={{ flexShrink: 0 }}
    >
      <path d={iconData.path} />
    </svg>
  );
}

// ─── Skill badge ─────────────────────────────────────────────────────────────

function SkillBadge({
  skill,
  index,
  isDark,
}: {
  skill: SkillDef;
  index: number;
  isDark: boolean;
}) {
  const iconData = ICONS[skill.name];
  const color =
    iconData?.kind === "svg"
      ? `#${iconData.hex}`
      : iconData?.kind === "img"
      ? iconData.color
      : "var(--accent)";

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.82 }}
      whileInView={{ opacity: 1, scale: 1 }}
      viewport={{ once: true }}
      transition={{ delay: index * 0.05, type: "spring", stiffness: 180, damping: 14 }}
      whileHover={{ y: -4, scale: 1.04 }}
      className="group flex flex-col items-center gap-2.5 p-3 sm:p-4 rounded-xl border border-[var(--border)] bg-[var(--background)] transition-all cursor-default hover:shadow-lg"
      style={{
        borderColor: undefined,
        // subtle hover border via outline to avoid layout shift
      }}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLElement).style.borderColor = color;
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLElement).style.borderColor = "";
      }}
    >
      {/* Icon wrapper */}
      <div
        className="w-11 h-11 sm:w-12 sm:h-12 rounded-lg flex items-center justify-center transition-transform group-hover:scale-110"
        style={{
          background: `color-mix(in srgb, ${color} 14%, transparent)`,
          border: `1px solid color-mix(in srgb, ${color} 25%, transparent)`,
        }}
      >
        {iconData ? (
          <SkillIcon iconData={iconData} isDark={isDark} size={26} />
        ) : (
          <span className="text-xs font-bold" style={{ color }}>
            {skill.name.slice(0, 2).toUpperCase()}
          </span>
        )}
      </div>

      {/* Label */}
      <div className="text-center">
        <span
          className="block text-[11px] sm:text-xs leading-tight font-medium"
          style={{ color: "var(--muted)" }}
        >
          {skill.name}
        </span>
        {skill.note && (
          <span
            className="block text-[9px] mt-0.5 font-medium"
            style={{ color }}
          >
            {skill.note}
          </span>
        )}
      </div>
    </motion.div>
  );
}

// ─── Section ─────────────────────────────────────────────────────────────────

export default function Skills() {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: "-80px" });
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme !== "light";

  return (
    <section id="skills" className="py-24 px-4" ref={ref}>
      <div className="max-w-6xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 24 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.5 }}
        >
          <div className="flex items-center gap-4 mb-12">
            <h2 className="font-heading text-3xl sm:text-4xl font-bold">Skills</h2>
            <div className="flex-1 h-px" style={{ background: "var(--border)" }} />
          </div>

          <div className="space-y-10">
            {skillGroups.map((group, gi) => (
              <motion.div
                key={group.category}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ delay: gi * 0.1 }}
              >
                <div className="flex items-center gap-3 mb-5">
                  <h3
                    className="text-xs font-semibold uppercase tracking-widest"
                    style={{ color: "var(--muted)" }}
                  >
                    {group.category}
                  </h3>
                  <div className="flex-1 h-px" style={{ background: "var(--border)" }} />
                </div>
                <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 gap-3">
                  {group.skills.map((skill, si) => (
                    <SkillBadge
                      key={skill.name + (skill.note ?? "")}
                      skill={skill}
                      index={si}
                      isDark={isDark}
                    />
                  ))}
                </div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>
    </section>
  );
}
